-- Fix: notify-session-created timezone display
-- Previously toLocaleTimeString() without timeZone used server UTC (Supabase Edge Functions run on UTC)
-- Now explicitly uses Europe/Madrid to display correct local time in notification content
-- This does NOT change any stored data, only the human-readable content generated by the Edge Function
--
-- Edge Function: notify-session-created (deployed to project ufutyjbqfjrlzkprvyvs)
-- Commit: 642a093 in /f/simplifica/supabase
--
-- Symptom: Notifications showed "14:30" instead of "16:30" for Madrid timezone bookings
-- Root cause: new Date(iso_string).toLocaleTimeString() uses server timezone without explicit timeZone option
-- Fix: Added timeZone: "Europe/Madrid" to toLocaleDateString() and toLocaleTimeString() calls
--
-- No schema changes - documentation only
SELECT 'No schema changes - Edge Function fix documented for future reference' as status;
